for i, c in enumerate(_codes):
    DBTI_TYPES[c] = {"name": _names[i], "desc": _descs[i]}

def get_dbti_code(a, l, r, p, th=50):
    return ("A" if a>=th else "D") + ("L" if l>=th else "E") + ("R" if r>=th else "S") + ("P" if p>=th else "Q")

_CODE_MAP = {}
for a_old in ["A","a"]:
  for l_old in ["L","l"]:
    for r_old in ["R","r"]:
      for p_old in ["P","p"]:
        old_code = a_old + l_old + r_old + p_old
        new_code = ("A" if a_old=="A" else "D") + ("L" if l_old=="L" else "E") + ("R" if r_old=="R" else "S") + ("P" if p_old=="P" else "Q")
        _CODE_MAP[new_code] = old_code

def get_dbti_info(a, l, r, p, th=50):
    new_code = get_dbti_code(a,l,r,p,th)
    old_code = _CODE_MAP.get(new_code, new_code)
    info = DBTI_TYPES.get(old_code)
    return (new_code, info["name"], info["desc"]) if info else (new_code, "自由辩手", "独特的辩论风格")


